// OpenMP equivalent of srad_cuda_1
void srad_omp_1(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float q0sqr)
{
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            float jc = J_cuda[index];

            int in = (i == 0) ? 0 : i - 1;
            int is = (i == rows - 1) ? rows - 1 : i + 1;
            int jw = (j == 0) ? 0 : j - 1;
            int je = (j == cols - 1) ? cols - 1 : j + 1;

            float n_val = J_cuda[in * cols + j] - jc;
            float s_val = J_cuda[is * cols + j] - jc;
            float w_val = J_cuda[i * cols + jw] - jc;
            float e_val = J_cuda[i * cols + je] - jc;

            float g2 = (n_val * n_val + s_val * s_val + w_val * w_val + e_val * e_val) / (jc * jc);
            float l = (n_val + s_val + w_val + e_val) / jc;

            float num = (0.5f * g2) - ((1.0f / 16.0f) * (l * l));
            float den = 1.0f + (0.25f * l);
            float qsqr = num / (den * den);

            // diffusion coefficient (equ 33)
            den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
            float cv = 1.0f / (1.0f + den);

            // saturate diffusion coefficient
            if (cv < 0.0f) cv = 0.0f;
            else if (cv > 1.0f) cv = 1.0f;

            C_cuda[index] = cv;
            E_C[index] = e_val;
            W_C[index] = w_val;
            S_C[index] = s_val;
            N_C[index] = n_val;
        }
    }
}

// OpenMP equivalent of srad_cuda_2
void srad_omp_2(
    float *E_C,
    float *W_C,
    float *N_C,
    float *S_C,
    float *J_cuda,
    float *C_cuda,
    int cols,
    int rows,
    float lambda,
    float q0sqr)
{
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int index = i * cols + j;

            float cc = C_cuda[index];

            int is = (i == rows - 1) ? rows - 1 : i + 1;
            int je = (j == cols - 1) ? cols - 1 : j + 1;

            float cn = cc;
            float cw = cc;
            float cs = C_cuda[is * cols + j];
            float ce = C_cuda[i * cols + je];

            // divergence (equ 58)
            float d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];

            // image update (equ 61)
            J_cuda[index] = J_cuda[index] + 0.25f * lambda * d_sum;
        }
    }
}

