#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>
#include <omp.h>
#include <pthread.h>

using namespace std;

/* this structure represents a point */
typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

/* this is the array of points */
typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

struct pkmedian_arg_t
{
  Points* points;
  long kmin;
  long kmax;
  long* kfinal;
  int pid;
  pthread_barrier_t* barrier;
};

class PStream {
public:
  virtual size_t read( float* dest, int dim, int num ) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {
  }
};

class SimStream : public PStream {
public:
  SimStream(long n_ ) {
    n = n_;
  }
  size_t read( float* dest, int dim, int num ) {
    size_t count = 0;
    for( int i = 0; i < num && n > 0; i++ ) {
      for( int k = 0; k < dim; k++ ) {
	dest[i*dim + k] = lrand48()/(float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() {
    return 0;
  }
  int feof() {
    return n <= 0;
  }
  ~SimStream() { 
  }
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen( filename, "rb");
    if( fp == NULL ) {
      fprintf(stderr,"error opening file %s\n.",filename);
      exit(1);
    }
  }
  size_t read( float* dest, int dim, int num ) {
    return std::fread(dest, sizeof(float)*dim, num, fp); 
  }
  int ferror() {
    return std::ferror(fp);
  }
  int feof() {
    return std::feof(fp);
  }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define PROFILE
#define CACHE_LINE 512

// GLOBAL
static bool *switch_membership;
static bool *is_center;
static int  *center_table;
static int nproc;
bool isCoordChanged;

// Timing Info
double serial_t;
double cpu_to_gpu_t;
double gpu_to_cpu_t;
double alloc_t;
double kernel_t;
double free_t;

#ifdef PROFILE
double time_local_search;
double time_speedy;
double time_select_feasible;
double time_gain;
double time_shuffle;
double time_gain_dist;
double time_gain_init;
#endif

// host memory
float *work_mem_h;
float *coord_h;

static int iter = 0;

//=======================================
// Euclidean Distance (host version)
//=======================================
static inline float
h_dist(int p1, int p2, int num, int dim, float *coord)
{
	float retval = 0.0;
	for(int i = 0; i < dim; i++){
		float tmp = coord[(i*num)+p1] - coord[(i*num)+p2];
		retval += tmp * tmp;
	}
	return retval;
}

void allocHostMem(int num, int dim)
{
	coord_h = (float*) malloc( num * dim * sizeof(float) );
}

void freeHostMem()
{
	free(coord_h);
}

void freeDevMem()
{
	// No device memory in OpenMP version
}

//=======================================
// pgain Entry - OpenMP version
//=======================================
float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
							double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{
	int stride	= *numcenters + 1;
	int K		= *numcenters;
	int num		=  points->num;
	int dim		=  points->dim;
	int nThread =  num;

	//=========================================
	// ALLOCATE HOST MEMORY + DATA PREPARATION
	//=========================================
	work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float));
	memset(work_mem_h, 0, stride * (nThread + 1) * sizeof(float));

	if(iter == 0)
	{
		allocHostMem(num, dim);
	}

	// build center-index table
	int count = 0;
	for( int i=0; i<num; i++)
	{
		if( is_center[i] )
		{
			center_table[i] = count++;
		}
	}

	// Extract 'coord'
	if(isCoordChanged || iter == 0)
	{
		for(int i=0; i<dim; i++)
		{
			for(int j=0; j<num; j++)
			{
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
			}
		}
	}

	// Initialize switch_membership
	memset(switch_membership, 0, num * sizeof(bool));

	//=======================================
	// PARALLEL KERNEL: CALCULATE COST
	//=======================================
	#pragma omp parallel for schedule(static)
	for(int tid = 0; tid < num; tid++)
	{
		float *lower = &work_mem_h[tid*stride];

		// cost between this point and point[x]: euclidean distance multiplied by weight
		float x_cost = h_dist(tid, (int)x, num, dim, coord_h) * points->p[tid].weight;

		// if computed cost is less then original (it saves), mark it as to reassign
		if ( x_cost < points->p[tid].cost )
		{
			switch_membership[tid] = 1;
			lower[K] += x_cost - points->p[tid].cost;
		}
		// if computed cost is larger, save the difference
		else
		{
			lower[center_table[points->p[tid].assign]] += points->p[tid].cost - x_cost;
		}
	}

	//=======================================
	// CPU (SERIAL) WORK
	//=======================================
	int number_of_centers_to_close = 0;
	float gl_cost_of_opening_x = z;
	float *gl_lower = &work_mem_h[stride * nThread];

	// compute the number of centers to close if we are to open i
	for(int i=0; i < num; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; j < num; j++ )
			{
				low += work_mem_h[ j*stride + center_table[i] ];
			}

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x += work_mem_h[i*stride+K];
	}

	// compute Euclidean distance (non-squared) for dist() calls
	// Note: dist() in original returns squared distance
	// We use the same dist() function here

	if ( gl_cost_of_opening_x < 0 )
	{
		for(int i = 0; i < num; i++)
		{
			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0;
			if ( switch_membership[i] || close_center )
			{
				// recompute cost using dist()
				float d = 0.0f;
				for(int k = 0; k < dim; k++) {
					float tmp = points->p[i].coord[k] - points->p[x].coord[k];
					d += tmp * tmp;
				}
				points->p[i].cost = d * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		for(int i = 0; i < num; i++)
		{
			if( is_center[i] && gl_lower[center_table[i]] > 0 )
			{
				is_center[i] = false;
			}
		}

		if( x >= 0 && x < num)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	//=======================================
	// DEALLOCATE HOST MEMORY
	//=======================================
	free(work_mem_h);

	iter++;
	return -gl_cost_of_opening_x;
}

