//=======================================
// Euclidean Distance (host version)
//=======================================
static inline float
d_dist_host(int p1, int p2, int num, int dim, float *coord)
{
	float retval = 0.0f;
	for(int i = 0; i < dim; i++){
		float tmp = coord[(i*num)+p1] - coord[(i*num)+p2];
		retval += tmp * tmp;
	}
	return retval;
}

