//=======================================
// Euclidean Distance (host version)
//=======================================
static inline float
h_dist(int p1, int p2, int num, int dim, float *coord_h)
{
	float retval = 0.0;
	for(int i = 0; dim > i; i++){
		float tmp = coord_h[(i*num)+p1] - coord_h[(i*num)+p2];
		retval = retval + (tmp * tmp);
	}
	return retval;
}

